import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

const Navbar = () => {
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`fixed top-0 w-full z-50 transition-all duration-300 ${
      isScrolled ? 'bg-white shadow-lg py-3' : 'bg-transparent py-5'
    }`}>
      <div className="container-custom">
        <div className="flex justify-between items-center">
          <Link to="/" className="text-2xl font-bold">
            <span className={isScrolled ? 'text-primary' : 'text-white'}>
              Swabhagya
            </span>
            <span className="text-secondary"> Realty</span>
          </Link>
          
          <div className="hidden md:flex space-x-8">
            <Link to="/" className={isScrolled ? 'text-gray-700 hover:text-primary' : 'text-white hover:text-secondary'}>
              Home
            </Link>
            <Link to="/about" className={isScrolled ? 'text-gray-700 hover:text-primary' : 'text-white hover:text-secondary'}>
              About
            </Link>
            <Link to="/projects" className={isScrolled ? 'text-gray-700 hover:text-primary' : 'text-white hover:text-secondary'}>
              Projects
            </Link>
            <Link to="/contact" className={isScrolled ? 'text-gray-700 hover:text-primary' : 'text-white hover:text-secondary'}>
              Contact
            </Link>
          </div>
          
          <a 
            href="https://wa.me/919876543210"
            target="_blank"
            rel="noopener noreferrer"
            className="bg-secondary text-white px-5 py-2 rounded-lg hidden md:block hover:bg-opacity-90 transition"
          >
            Enquire Now
          </a>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
